    private final String iconName;

    LucideIcon(String iconName) {
        this.iconName = iconName;
    }

    /**
     * Returns the Lucide icon file name (without {@code .svg} extension).
     *
     * @return the icon name in kebab-case
     */
    public String getIconName() {
        return iconName;
    }

    /**
     * Creates a new {@link LucideSvgIcon} for this icon.
     *
     * @return a new icon component
     */
    public LucideSvgIcon create() {
        return LucideIconFactory.create(iconName);
    }
